                // Generate all combinations of characters of the given length
                Set<InnerType> charVals = this.charNode.genExVals();
                List<InnerType> charList = new ArrayList<>(charVals);

                // Generate all combinations with replacement (cartesian product)
                generateCombinations(charList, length, new ArrayList<>(), result);
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of characters with a given length.
     * Uses recursion to build combinations with replacement.
     *
     * @param chars the list of available characters
     * @param length the desired length of the combination
     * @param current the current combination being built
     * @param result the set to add completed combinations to
     */
    private void generateCombinations(List<InnerType> chars, int length,
                                     List<InnerType> current,
                                     Set<PyStringObj<InnerType>> result) {
        if (current.size() == length) {
            result.add(new PyStringObj<>(new ArrayList<>(current)));
            return;
        }

        for (InnerType ch : chars) {
            current.add(ch);
            generateCombinations(chars, length, current, result);
            current.remove(current.size() - 1);
        }
    }

    @Override
    public PyStringObj<InnerType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyStringObj<>(new ArrayList<>());
        }

        // Pick a random length from the domain
        Random rand = new Random();
        int length = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        // Generate a string of that length with random characters
        List<InnerType> string = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            string.add(this.charNode.genRandVal());
        }

        return new PyStringObj<>(string);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node representing Python dictionaries that can generate dictionary values of various sizes.
 * The domain is specified as a list of integers representing the sizes of dictionaries to generate.
 * Dictionaries have two child nodes: one for keys and one for values.
 *
 * @param <KeyType> the type of keys in the dictionary
 * @param <ValueType> the type of values in the dictionary
 */
public class PyDictNode<KeyType extends APyObj, ValueType extends APyObj>
    extends AIterablePyNode<PyDictObj<KeyType, ValueType>> {

    private APyNode<?, KeyType> keyNode;
    private APyNode<?, ValueType> valueNode;
    private List<Integer> exDomain;
    private List<Integer> ranDomain;

    /**
     * Constructor for PyDictNode with given key and value nodes.
     *
     * @param keyNode the node representing the type of keys in the dictionary
     * @param valueNode the node representing the type of values in the dictionary
     */
    public PyDictNode(APyNode<?, KeyType> keyNode, APyNode<?, ValueType> valueNode) {
        this.keyNode = keyNode;
        this.valueNode = valueNode;
        this.exDomain = new ArrayList<>();
        this.ranDomain = new ArrayList<>();
    }

    @Override
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    @Override
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    @Override
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    @Override
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    @Override
    public APyNode<?, ?> getLeftChild() {
        return this.keyNode;
    }

    @Override
    public APyNode<?, ?> getRightChild() {
        return this.valueNode;
    }

    @Override
    public Set<PyDictObj<KeyType, ValueType>> genExVals() {
        Set<PyDictObj<KeyType, ValueType>> result = new HashSet<>();

        // Generate all combinations of key-value pairs for each size in the domain
        for (Integer size : this.exDomain) {
            if (size == 0) {
                // Empty dict
                result.add(new PyDictObj<>(new HashMap<>()));
            } else {
                // Generate all combinations of key-value pairs of the given size
                Set<KeyType> keyVals = this.keyNode.genExVals();
                Set<ValueType> valueVals = this.valueNode.genExVals();
                List<KeyType> keyList = new ArrayList<>(keyVals);
                List<ValueType> valueList = new ArrayList<>(valueVals);

                if (size <= keyList.size()) {
                    // Generate all combinations of key-value pairs without key replacement
                    generateCombinations(keyList, valueList, size, new HashMap<>(), 0, result);
                }
            }
        }

        return result;
    }

    /**
     * Helper method to generate all combinations of key-value pairs.
     * Keys must be unique (no replacement), values can repeat.
     *
     * @param keys the list of available keys
     * @param values the list of available values
     * @param size the desired size of the dictionary
     * @param current the current dictionary being built
     * @param startKeyIdx the index to start considering keys from
     * @param result the set to add completed dictionaries to
     */
    private void generateCombinations(List<KeyType> keys, List<ValueType> values,
                                     int size, Map<KeyType, ValueType> current,
                                     int startKeyIdx,
                                     Set<PyDictObj<KeyType, ValueType>> result) {
        if (current.size() == size) {
            result.add(new PyDictObj<>(new HashMap<>(current)));
            return;
        }

        for (int i = startKeyIdx; i < keys.size(); i++) {
            KeyType key = keys.get(i);
            for (ValueType value : values) {
                current.put(key, value);
                generateCombinations(keys, values, size, current, i + 1, result);
                current.remove(key);
            }
        }
    }

    @Override
    public PyDictObj<KeyType, ValueType> genRandVal() {
        if (this.ranDomain.isEmpty()) {
            return new PyDictObj<>(new HashMap<>());
        }

        // Pick a random size from the domain
        Random rand = new Random();
        int size = this.ranDomain.get(rand.nextInt(this.ranDomain.size()));

        // Generate a dictionary of that size with random key-value pairs
        Map<KeyType, ValueType> dict = new HashMap<>();
        Set<KeyType> keyVals = this.keyNode.genExVals();
        List<KeyType> keyList = new ArrayList<>(keyVals);

        // Generate random unique keys (without replacement)
        if (size > 0 && !keyList.isEmpty()) {
            // Shuffle the key list and pick the first 'size' keys
            Collections.shuffle(keyList);
            for (int i = 0; i < Math.min(size, keyList.size()); i++) {
                KeyType key = keyList.get(i);
                ValueType value = this.valueNode.genRandVal();
                dict.put(key, value);
            }
        }

        return new PyDictObj<>(dict);
    }
}

