package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * A generator that creates test cases from node specifications.
 * Generates both exhaustive test cases (all possible combinations) and random test cases.
 */
public class BaseSetGenerator {

    private final List<APyNode<?, ?>> nodes;
    private final int numRand;
    private Set<TestCase> currentTests;

    /**
     * Constructor for BaseSetGenerator.
     *
     * @param nodes the list of argument nodes
     * @param numRand the number of random tests to generate
     */
    public BaseSetGenerator(List<APyNode<?, ?>> nodes, int numRand) {
        this.nodes = new ArrayList<>(nodes);
        this.numRand = numRand;
        this.currentTests = new HashSet<>();
    }

    /**
     * Generates all exhaustive test cases by computing the Cartesian product
     * of exhaustive values from all argument nodes.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        this.currentTests = new HashSet<>();

        if (this.nodes.isEmpty()) {
            return this.currentTests;
        }

        // Generate all exhaustive values for each node
        List<Set<APyObj>> allValues = new ArrayList<>();
        for (APyNode<?, ?> node : this.nodes) {
            Set<? extends APyObj> vals = node.genExVals();
            allValues.add(new HashSet<>(vals));
        }

        // Compute Cartesian product
        generateCartesianProduct(allValues, 0, new ArrayList<>(), this.currentTests);

        return new HashSet<>(this.currentTests);
    }

    /**
     * Helper method to generate the Cartesian product of multiple sets.
     *
     * @param allValues list of value sets for each argument
     * @param index current argument index
     * @param current current combination being built
     * @param result set to add completed combinations to
     */
    private void generateCartesianProduct(List<Set<APyObj>> allValues, int index,
                                         List<APyObj> current, Set<TestCase> result) {
        if (index == allValues.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }

        for (APyObj val : allValues.get(index)) {
            current.add(val);
            generateCartesianProduct(allValues, index + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates random test cases.
     * The number of tests to generate is determined by numRand passed to the constructor.
     *
     * @return a set of random test cases (up to numRand tests)
     */
    public Set<TestCase> genRandTests() {
        Set<TestCase> result = new HashSet<>();

        for (int i = 0; i < this.numRand; i++) {
            TestCase test = genRandTest();
            // Avoid duplicates with exhaustive tests
            if (!this.currentTests.contains(test)) {
                result.add(test);
            }
        }

        return result;
    }

    /**
     * Helper method to generate a single random test case.
     *
     * @return a random test case
     */
    private TestCase genRandTest() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?, ?> node : this.nodes) {
            args.add(node.genRandVal());
        }
        return new TestCase(args);
    }

    /**
     * Generates the base set of tests: all exhaustive tests plus random tests.
     * Returns a list combining genExTests() and genRandTests().
     *
     * @return a list of all exhaustive and random test cases
     */
    public List<TestCase> genBaseSet() {
        // First generate exhaustive tests
        Set<TestCase> exTests = genExTests();

        // Then generate random tests
        Set<TestCase> randTests = genRandTests();

        // Combine and return as list
        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(randTests);

        return result;
    }
}

