import java.util.*;

/**
 * A node representing Python strings that can generate string values of various lengths.
 * The domain is specified as a list of integers representing the lengths of strings to generate.
 * Strings allow duplicate characters and work with PyCharObj.
 */
public class PyStringNode extends AIterablePyNode<PyStringObj> {

